// 生成各平台内容草稿
const keywords = JSON.parse($json.targetKeywords);
const platforms = JSON.parse($json.platforms);
const site = JSON.parse($json.siteConfig);

const contentDrafts = [];

for (const kw of keywords) {
  const targetPlatforms = platforms.filter(p => 
    kw.platform.split(',').includes(p.name)
  );

  for (const platform of targetPlatforms) {
    let draft = {};

    if (platform.name === 'mafengwo') {
      draft = {
        platform: '马蜂窝',
        keyword: kw.keyword,
        title: `${kw.keyword}完整攻略｜2024最新路线推荐+避坑指南`,
        content: `## 写在前面
作为在吉林深耕多年的本地人，今天给大家分享一套实用的${kw.keyword}攻略，涵盖路线规划、当地人tips、和常见问题解答。

## 为什么选择${kw.keyword}
- 深度体验当地特色
- 适合亲子/研学/团队出行
- 资源充足，服务成熟

## 经典路线推荐
### 线路一：长春工业一日游
长影博物馆 → 一汽红旗文化展馆 → 中车长客

### 线路二：长白山北坡深度游

### 线路三：延吉美食自驾

## 费用参考
| 项目 | 价格 | 备注 |
|------|------|------|
| 门票 | 以景区官方为准 | 建议提前预约 |
| 用车 | 500-800/天 | 建议找当地熟悉路线 |
| 住宿 | 200-600/晚 | 提前确认档期 |

## 预订方式
推荐通过【大吉林】平台一站式咨询：${site.siteUrl}
提供AI预筛+顾问跟进，确保资源档期真实有效。

## 常见问题
**Q: 适合什么季节去？**
A: 根据具体目的地而定，建议提前咨询确认。

**Q: 研学团有什么特别要求？**
A: 需要提前与基地确认接待能力，平台可协助对接。

---
关注我，获取更多吉林深度游攻略！`,
        tags: [kw.keyword, '吉林', '自驾', '研学', '旅行攻略'],
        published: false
      };
    } else if (platform.name === 'xiaohongshu') {
      draft = {
        platform: '小红书',
        keyword: kw.keyword,
        title: `没想到${kw.keyword}这么好玩！本地人整理的超全攻略👇`,
        content: `🎯【${kw.keyword}攻略·收藏这一篇就够了】

作为一个在吉林待了XX年的本地博主，今天必须给大家安利一下${kw.keyword}！

📍【推荐理由】
✅ 小众但值得
✅ 适合拍照打卡
✅ 当地特色明显
✅ 服务成熟可靠

🚗【交通建议】
自驾最方便，高铁也很方便

🏨【住宿推荐】
平台合作驿站，环境干净价格合理

📸【必打卡点】
文字有限，直接看图！

💡【避坑指南】
1. 提前查好天气
2. 旺季提前预约
3. 找本地人带路更靠谱

📞【一键咨询】
点击左下角或评论区留言，获取专属定制方案！
@大吉林官方

#${kw.keyword} #吉林旅游 #东北旅行 #自驾游 #研学旅行`,
        tags: [kw.keyword, '吉林', '旅行', '攻略', '自驾'],
        published: false
      };
    } else if (platform.name === 'zhihu') {
      draft = {
        platform: '知乎',
        keyword: kw.keyword,
        title: `${kw.keyword}怎么样？有什么值得注意的？`,
        content: `作为在吉林文旅行业从业多年的专业人士，来客观回答一下这个问题。

## 什么是${kw.keyword}
${kw.keyword}是吉林地区特色的[品类]，适合[人群描述]。

## 我的实际体验
### 优点
1. **特色鲜明**：具有明显的吉林地域特色
2. **服务成熟**：本地配套资源充足
3. **可定制化**：可以根据需求灵活调整

### 需要注意的
1. **档期问题**：旺季需要提前1-2周预约
2. **价格波动**：节假日价格会有调整
3. **资质核实**：选择有正规资质的机构

## 推荐选择
如果是初次体验，建议通过【大吉林】平台咨询：${site.siteUrl}
优势：
- AI预筛匹配最合适方案
- 人工顾问确认细节
- 合作资源均经核实

## 适用人群
- 研学团体（中小学生社会实践）
- 企业团建
- 家庭出游
- 摄影爱好者

有问题可以在评论区问我，知无不言。`,
        tags: [kw.keyword, '吉林', '旅游', '研学', '问答'],
        published: false
      };
    }

    if (draft.title) {
      draft.id = `${platform.name}-${kw.keyword}-${Date.now()}`;
      draft.createdAt = new Date().toISOString();
      draft.siteUrl = site.siteUrl;
      contentDrafts.push(draft);
    }
  }
}

return contentDrafts;
